  assign HEX7 = ~display.hex7;

  generate 
    genvar seg_select;
    for(seg_select=0; seg_select < 8; seg_select= seg_select + 1)
    begin: seven_seg_display_controller
      always_comb
      begin
        casez(gen_bus_if.rdata[31-seg_select*4:(31-(seg_select+1)*4) + 1])
